using Microsoft.AspNetCore.Mvc;\nusing System.Collections.Generic;\nusing System.Linq;\nusing System.Threading.Tasks;\n\nnamespace ApexCustomClothiers.Controllers\n{\n    [Route("api/[controller]")]\n    [ApiController]\n    public class ServicesController : ControllerBase\n    {\n        private static List<Service> Services = new List<Service>();\n\n        // GET: api/services\n        [HttpGet]\n        public ActionResult<IEnumerable<Service>> GetAll()\n        {\n            return Ok(Services);\n        }\n\n        // GET: api/services/{id}\n        [HttpGet("{id}")]\n        public ActionResult<Service> GetById(int id)\n        {\n            var service = Services.FirstOrDefault(s => s.Id == id);\n            if (service == null)\n                return NotFound();\n            return Ok(service);\n        }\n\n        // POST: api/services\n        [HttpPost]\n        public ActionResult<Service> Create(Service service)\n        {\n            service.Id = Services.Count > 0 ? Services.Max(s => s.Id) + 1 : 1;\n            Services.Add(service);\n            return CreatedAtAction(nameof(GetById), new { id = service.Id }, service);\n        }\n\n        // PUT: api/services/{id}\n        [HttpPut("{id}")]\n        public ActionResult Update(int id, Service service)\n        {\n            var existingService = Services.FirstOrDefault(s => s.Id == id);\n            if (existingService == null)\n                return NotFound();\n            existingService.Name = service.Name; // Update properties as needed\n            return NoContent();\n        }\n\n        // DELETE: api/services/{id}\n        [HttpDelete("{id}")]\n        public ActionResult Delete(int id)\n        {\n            var service = Services.FirstOrDefault(s => s.Id == id);\n            if (service == null)\n                return NotFound();\n            Services.Remove(service);\n            return NoContent();\n        }\n    }\n    public class Service\n    {\n        public int Id { get; set; }\n        public string Name { get; set; } // Add other properties as needed\n    }\n}